// Parse services from Wix REST API v2 response
const raw = $input.first().json;
const services = raw.services || [];

const parsed = services.map(svc => ({
  wix_id: svc.id || '',
  service_type: svc.type || 'BOOKING_SERVICE',
  title: svc.name || svc.info?.name || 'Unknown Service',
  price: 0.0, // v2 API price is in paymentOptions, simplified here
  status: svc.status || 'ACTIVE',
  category: svc.category?.name || null,
  duration: svc.schedule?.availabilityConstraints?.sessionDurations?.[0] || null
}));

return [{ json: { services: parsed, count: parsed.length } }];

// Parse bookings from Wix REST API v2 response
const raw = $input.first().json;
const bookings = raw.bookings || [];
const total = raw.pagingMetadata?.total || bookings.length;

const parsed = bookings.map(b => {
  const details = b.contactDetails || {};
  const contact_id = b.contactId || details.contactId || '';
  const email = (details.email || '').trim().toLowerCase();
  const wix_cid = contact_id || email;
  const full_name = `${details.firstName || ''} ${details.lastName || ''}`.trim() || 'Guest';
  const phone = details.phone || '';
  const wix_service_id = b.bookedEntity?.slot?.serviceId || '';

  // Price parsing — handle strings like "EGP 600"
  let amount_paid = 0.0;
  try {
    const price_info = b.priceInfo || {};
    const total_price_obj = price_info.totalPrice || {};
    const raw_price = 'value' in total_price_obj ? total_price_obj.value : (price_info.totalPrice || 0);
    if (typeof raw_price === 'string') {
      const clean = raw_price.replace(/[^\d.]/g, '');
      amount_paid = clean ? parseFloat(clean) : 0.0;
    } else {
      amount_paid = parseFloat(raw_price) || 0.0;
    }
  } catch(e) { amount_paid = 0.0; }

  return {
    wix_booking_id: b.id || '',
    wix_contact_id: wix_cid,
    full_name, email, phone,
    wix_service_id,
    registration_date: b.createdDate || new Date().toISOString(),
    amount_paid,
    status: b.status || 'CONFIRMED'
  };
}).filter(b => b.wix_contact_id); // drop records with no identity

return [{ json: { bookings: parsed, total, fetched: bookings.length } }];

// Merge services and bookings results into a single payload for the upsert endpoint
const services = $('Parse Services').first().json.services || [];
const bookings = $('Parse Bookings').first().json.bookings || [];
const total = $('Parse Bookings').first().json.total || 0;

return [{
  json: {
    services,
    bookings,
    meta: {
      sync_at: new Date().toISOString(),
      services_count: services.length,
      bookings_fetched: bookings.length,
      bookings_total: total
    }
  }
}];

const result = $input.first().json;
const meta = $('Merge Payload').first().json.meta;

const success = result.status === 'ok' || result.synced !== undefined;
const summary = {
  status: success ? 'SUCCESS' : 'PARTIAL',
  synced_at: meta.sync_at,
  services_synced: result.services_synced ?? meta.services_count,
  bookings_synced: result.bookings_synced ?? meta.bookings_fetched,
  bookings_total_in_wix: meta.bookings_total,
  error: result.error || null
};

console.log('[WixCacheSync]', JSON.stringify(summary));
return [{ json: summary }];

// SUCCESS path — emit clean summary
const s = $json;
return [{ json: {
  result: 'ok',
  message: `Wix Cache Sync complete: ${s.services_synced} services, ${s.bookings_synced} bookings synced at ${s.synced_at}`
}}];

// FAILURE path — emit alert
const s = $json;
return [{ json: {
  result: 'error',
  message: `Wix Cache Sync had issues at ${s.synced_at}. Error: ${s.error || 'unknown'}. Check Cabinet API logs.`
}}];
